fn print_bytes(data: impl AsRef<[u8]>) {
    for byte in data.as_ref() {
        print!("{byte:02x} ");
    }
    println!();
}
print_bytes("hello");        // &str implements AsRef<[u8]>
print_bytes(vec![1, 2, 3]);  // Vec<u8> implements AsRef<[u8]>
print_bytes(&[4, 5, 6]);     // &[u8] implements AsRef<[u8]>

